    id: 12, slug: 'lobuche-peak', name: 'Lobuche Peak', nameHe: 'טיפוס ללובוצ׳ה פיק', country: 'Nepal', countryHe: 'נפאל', flag: '🇳🇵',
    ghlCalendarId: 'Ala9X5mln6i45N30Xhpm',
